import anthropic, json

client = anthropic.Anthropic()

RISK_REGISTER_TOOL = {
    "name": "generate_risk_register",
    "description": "Populate a feature risk register from FMEA results and additional risk analysis",
    "input_schema": {
        "type": "object",
        "required": ["register_id", "feature_id", "feature_name",
                     "created_date", "risks", "summary"],
        "properties": {
            "register_id": {"type": "string"},
            "feature_id": {"type": "string"},
            "feature_name": {"type": "string"},
            "created_date": {"type": "string"},
            "last_updated": {"type": "string"},
            "risks": {
                "type": "array",
                "items": {
                    "type": "object",
                    "required": ["id", "category", "title", "description",
                                 "likelihood", "severity", "rpn", "owner",
                                 "status", "mitigation", "release_gate"],
                    "properties": {
                        "id": {"type": "string"},
                        "category": {
                            "enum": ["output_quality", "safety_ethics",
                                     "operational", "technical", "compliance"]
                        },
                        "title": {"type": "string"},
                        "description": {"type": "string"},
                        "likelihood": {"enum": ["low", "medium", "high", "very_high", "near_certain"]},
                        "severity": {"enum": ["negligible", "minor", "moderate", "major", "critical"]},
                        "rpn": {"type": "integer"},
                        "owner": {"type": "string"},
                        "status": {"enum": ["OPEN", "MITIGATED", "ACCEPTED", "BLOCKED"]},
                        "mitigation": {"type": "string"},
                        "residual_likelihood": {"enum": ["low", "medium", "high", "very_high", "near_certain"]},
                        "residual_severity": {"enum": ["negligible", "minor", "moderate", "major", "critical"]},
                        "residual_rpn": {"type": "integer"},
                        "release_gate": {"type": "string"}
                    }
                }
            },
            "summary": {
                "type": "object",
                "properties": {
                    "total_risks": {"type": "integer"},
                    "open_risks": {"type": "integer"},
                    "mitigated_risks": {"type": "integer"},
                    "accepted_risks": {"type": "integer"},
                    "blocked_risks": {"type": "integer"},
                    "release_recommendation": {
                        "enum": ["APPROVE", "APPROVE_WITH_MONITORING",
                                 "APPROVE_WITH_CONDITIONS", "BLOCK"]
                    }
                }
            }
        }
    }
}

def generate_risk_register(feature_id, feature_name, fmea_results, feature_spec):
    from datetime import datetime
    today = datetime.today().strftime("%Y-%m-%d")

    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=4096,
        tools=[RISK_REGISTER_TOOL],
        tool_choice={"type": "tool", "name": "generate_risk_register"},
        messages=[{
            "role": "user",
            "content": (
                f"Generate a risk register for feature {feature_id}: {feature_name}.\n\n"
                f"FMEA results (use as primary source for risks):\n{json.dumps(fmea_results, indent=2)}\n\n"
                f"Feature spec (use to identify compliance / scope risks):\n{json.dumps(feature_spec, indent=2)}\n\n"
                f"Today: {today}\n\n"
                "Rules:\n"
                "- Convert each FMEA failure mode into a risk entry\n"
                "- Add risks from the five categories that FMEA may have missed (compliance, operational)\n"
                "- RPN = likelihood_score × severity_score (low=1, medium=3, high=5, very_high=8, near_certain=10)\n"
                "- release_gate must be a specific, measurable condition (not 'monitor it')\n"
                "- release_recommendation: BLOCK if any OPEN risk has severity=critical or RPN > 500"
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

RELEASE_GATE_TOOL = {
    "name": "evaluate_release_gate",
    "description": "Evaluate whether a feature is safe to release based on its risk register",
    "input_schema": {
        "type": "object",
        "required": ["gate_decision", "blocking_risks", "monitored_risks",
                     "conditions", "gate_rationale"],
        "properties": {
            "gate_decision": {"enum": ["PASS", "PASS_WITH_CONDITIONS", "BLOCK"]},
            "blocking_risks": {
                "type": "array",
                "description": "Risk IDs that prevent release",
                "items": {"type": "string"}
            },
            "monitored_risks": {
                "type": "array",
                "description": "Risk IDs that will be tracked post-launch",
                "items": {
                    "type": "object",
                    "properties": {
                        "risk_id": {"type": "string"},
                        "metric": {"type": "string"},
                        "alert_threshold": {"type": "string"}
                    }
                }
            },
            "conditions": {
                "type": "array",
                "description": "Conditions required before deployment (for PASS_WITH_CONDITIONS)",
                "items": {"type": "string"}
            },
            "gate_rationale": {"type": "string"}
        }
    }
}

def evaluate_release_gate(risk_register):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[RELEASE_GATE_TOOL],
        tool_choice={"type": "tool", "name": "evaluate_release_gate"},
        messages=[{
            "role": "user",
            "content": (
                f"Evaluate the release gate for this risk register.\n\n"
                f"{json.dumps(risk_register, indent=2)}\n\n"
                "Rules:\n"
                "- BLOCK if: any OPEN risk with severity=critical, OR overall RPN sum > 2000 for open risks\n"
                "- PASS_WITH_CONDITIONS if: any OPEN risk with severity=major and status=OPEN\n"
                "- PASS if: all risks are MITIGATED or ACCEPTED and no critical open risks remain\n"
                "For each monitored risk, define a specific metric and alert threshold."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")

import anthropic, json

client = anthropic.Anthropic()

INCIDENT_UPDATE_TOOL = {
    "name": "update_register_from_incident",
    "description": "Update a risk register entry based on a production incident",
    "input_schema": {
        "type": "object",
        "required": ["updated_risk_id", "new_status", "incident_reference",
                     "updated_likelihood", "updated_rpn", "revised_mitigation"],
        "properties": {
            "updated_risk_id": {"type": "string"},
            "new_status": {"enum": ["OPEN", "MITIGATED", "ACCEPTED"]},
            "incident_reference": {"type": "string"},
            "updated_likelihood": {
                "enum": ["low", "medium", "high", "very_high", "near_certain"]
            },
            "updated_rpn": {"type": "integer"},
            "revised_mitigation": {"type": "string"},
            "new_release_gate": {"type": "string"}
        }
    }
}

def update_register_from_incident(risk_register, incident_report):
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=1024,
        tools=[INCIDENT_UPDATE_TOOL],
        tool_choice={"type": "tool", "name": "update_register_from_incident"},
        messages=[{
            "role": "user",
            "content": (
                f"Update the risk register based on this production incident.\n\n"
                f"Incident:\n{json.dumps(incident_report, indent=2)}\n\n"
                f"Current risk register (risks section):\n"
                f"{json.dumps(risk_register['risks'], indent=2)}\n\n"
                "Find the risk entry that most closely matches the incident. "
                "If the incident occurred despite a MITIGATED status, increase likelihood. "
                "Add the incident reference to the updated entry. "
                "Revise the mitigation and release gate to prevent recurrence."
            )
        }]
    )
    for block in response.content:
        if block.type == "tool_use":
            return block.input
    raise RuntimeError("No tool use in response")
